<div class="d-flex justify-content-between align-items-center mb-4"><div><h2 class="h3 fw-bold mb-1">Mis evaluaciones</h2><p class="text-muted mb-0">Evaluaciones creadas para tus materias asignadas.</p></div><a href="<?= e(url('/profesor/evaluaciones/crear')) ?>" class="btn btn-primary">Nueva evaluacion</a></div>
